class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)

        def cost(l, r):
            t = s[l:r+1]
            m = r - l + 1
            best = m
            for d in range(1, m):
                if m % d: continue
                total = 0
                for i in range(d):
                    left, right = i, m - d + i
                    while left < right:
                        if t[left] != t[right]:
                            total += 1
                        left += d
                        right -= d
                best = min(best, total)
            return best

        dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for j in range(1, k + 1):
                for l in range(i):
                    dp[i][j] = min(dp[i][j], dp[l][j - 1] + cost(l, i - 1))

        return dp[n][k]

